class MyQueue {
    Stack<Integer> in = new Stack<>(), out = new Stack<>();
    void push(int x) { in.push(x); }
    int pop() {
        if (out.isEmpty()) while (!in.isEmpty()) out.push(in.pop());
        return out.pop();
    }
}

