class MyQueue {
    stack<int> in, out;
public:
    void push(int x) { in.push(x); }
    int pop() {
        if (out.empty()) while (!in.empty()) { out.push(in.top()); in.pop(); }
        int val = out.top(); out.pop(); return val;
    }
};
